<template>
  <div class="goodsShareSetting">
    <SpPlatformTip />
    <el-form ref="form" label-width="180px" :rules="rules" :model="form">
      <el-form-item label="商品分享是否限製">
        <el-switch v-model="form.is_open" />
      </el-form-item>
      <template v-if="form.is_open">
        <el-form-item label="可分享會員等級" prop="valid_grade">
          <el-checkbox-group v-model="form.valid_grade">
            <el-checkbox v-for="grade in memberGrade" :key="grade.grade_id" :label="grade.grade_id">
              {{ grade.grade_name }}
            </el-checkbox>
            <el-checkbox
              v-for="vipdata in vipGrade"
              :key="vipdata.lv_type"
              :label="vipdata.lv_type"
            >
              {{ vipdata.grade_name }}
            </el-checkbox>
          </el-checkbox-group>
        </el-form-item>
        <el-form-item label="分享限製提示語" prop="msg">
          <el-input
            v-model="form.msg"
            style="width: 260px"
            type="text"
            placeholder="請輸入分享限製提示語"
          />
        </el-form-item>
        <el-form-item label="提示後跳轉頁麵路徑" prop="page">
          <div class="path" @click="showSetLink">
            <span v-show="form.page.linkPage" class="pathTitle">{{ linkPage }}:</span>
            {{ form.page.title ? form.page.title : '設置路徑' }}
          </div>
        </el-form-item>
      </template>
      <el-form-item>
        <el-button type="primary" @click="save"> 保存 </el-button>
      </el-form-item>
    </el-form>

    <linkSetter :visible="linksVisible" @setLink="setLink" @closeDialog="closeDialog" />
  </div>
</template>

<script>
import linkSetter from '@/components/template_links'
import { listVipGrade } from '../../../api/cardticket'
import { getGradeList } from '../../../api/membercard'
import { getShareSetting, saveShareSetting } from '../../../api/goods'

export default {
  name: 'GoodsShareSetting',
  components: {
    linkSetter
  },
  data() {
    return {
      // 設置路徑
      linksVisible: false,
      form: {
        is_open: false,
        valid_grade: [],
        msg: '當前等級無法分享',
        page: {}
      },
      rules: {
        valid_grade: [{ required: true, message: '請選擇可以分享的會員等級', trigger: 'blur' }],
        msg: [{ required: true, message: '請輸入分享限製提示語', trigger: 'blur' }],
        page: [{ required: true, message: '請選擇跳轉頁麵路徑', trigger: 'change' }]
      },
      vipGrade: [],
      memberGrade: []
    }
  },
  computed: {
    linkPage({ form }) {
      const { page } = form
      const types = {
        goods: '商品',
        category: '分類',
        article: '文章',
        planting: '軟文',
        link: '頁麵',
        marketing: '營銷',
        custom_page: '自定義頁麵',
        other_wxapp: '小程序'
      }
      return types[page.linkPage]
    }
  },
  mounted() {
    this.init()
  },
  methods: {
    async init() {
      // 獲取會員列表
      const grade = await getGradeList()
      const vip_grade = await listVipGrade()
      this.vipGrade = vip_grade.data.data
      this.memberGrade = grade.data.data
      this.getShareSettingInfo()
    },
    // 獲取分享配置
    async getShareSettingInfo() {
      // 獲取分享配置
      const data = await getShareSetting()
      this.form = { ...data.data.data }
      if (!this.form.page || Array.isArray(this.form.page)) {
        this.$set(this.form, 'page', {})
      }
      if (!this.form.valid_grade) {
        this.$set(this.form, 'valid_grade', [])
      }
      if (!this.form.msg) {
        this.$set(this.form, 'msg', '')
      }
    },
    showSetLink() {
      this.linksVisible = true
    },
    setLink(links, type) {
      this.$set(this.form, 'page', { ...links, linkPage: type })
    },
    closeDialog() {
      this.linksVisible = false
    },
    // 保存表單
    save() {
      this.$refs['form'].validate(async (vaild) => {
        if (vaild) {
          const { form } = this
          const data = await saveShareSetting(form)
          if (data.data.data.status) {
            this.$message.success('保存成功')
            this.getShareSettingInfo()
          }
        }
      })
    }
  }
}
</script>

<style lang="scss" scoped>
.goodsShareSetting {
  width: 100%;
  height: 100%;
  .pathTitle {
    margin-right: 10px;
  }
  .path {
    padding: 0 10px;
    height: 40px;
    line-height: 40px;
    color: #666;
    border: 1px dashed #dfdfdf;
    display: inline-block;
    min-width: 180px;
    text-align: center;
  }
}
</style>
